func NewInternalHandlers(next serviceManager, apiHandler, rest, metricsHandler, pingHandler, dashboard, acmeHTTP http.Handler) *InternalHandlers {
	return &InternalHandlers{
		api:		apiHandler,
		dashboard:	dashboard,
		rest:		rest,
		prometheus:	metricsHandler,
		ping:		pingHandler,
		acmeHTTP:	acmeHTTP,
		serviceManager:	next,
	}
}
